INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ras. 4 - O trabalho a favor da comunidade pode ser prestado aos sábados, domingos e feriados, bem como nos dias úteis, mas neste caso os períodos de trabalho não podem prejudicar a jornada normal de trabalho, nem exceder, por dia, o permitido segundo o regime de horas extraordinárias aplicável. 
